mapper.select:
SELECT st.结算单编号 AS settlementId, st.结算单单号 AS settlementCode, c.合同编号 AS contractId, CONCAT(DATE_FORMAT(st.结算周期起, '%Y-%m-%d'), ' 至 ', DATE_FORMAT(st.结算周期止, '%Y-%m-%d')) AS settlementPeriod, st.结算金额 AS settlementAmount, st.已付金额 AS settlementPaidAmount, COALESCE(es.员工姓名, st.制单人编码) AS settlementCreatedBy FROM SETTLEMENT st LEFT JOIN CONTRACT c ON c.合同号 = st.合同号 LEFT JOIN EMPLOYEE es ON es.员工编码 = st.制单人编码 WHERE st.结算类型 = 'PAYABLE' AND c.合同编号 IN
#{id}
ORDER BY c.合同编号 ASC, st.结算单编号 ASC

SELECT inv.发票编号 AS invoiceId, inv.发票号码 AS invoiceNumber, inv.开票日期 AS invoiceDate, inv.金额 AS invoiceAmount, inv.税额 AS taxAmount, (inv.金额 + COALESCE(inv.税额, 0)) AS totalAmount, rel.关系编号 AS apDetailId, rel.关联金额 AS relatedAmount, rel.关联时间 AS relatedTime, st.结算单编号 AS settlementId, COALESCE(ei.员工姓名, inv.创建人编码) AS invoiceCreatedBy, COALESCE(ear.员工姓名, rel.创建人编码) AS apCreatedBy FROM SETTLEMENT_INVOICE_REL rel LEFT JOIN INVOICE inv ON inv.发票编号 = rel.发票编号 LEFT JOIN SETTLEMENT st ON st.结算单编号 = rel.结算单编号 LEFT JOIN EMPLOYEE ei ON ei.员工编码 = inv.创建人编码 LEFT JOIN EMPLOYEE ear ON ear.员工编码 = rel.创建人编码 WHERE st.结算单编号 IN
#{id}
AND rel.status != 'CANCELLED' ORDER BY st.结算单编号 ASC, inv.发票编号 ASC

SELECT c.合同编号 AS contractId, CASE WHEN COUNT(DISTINCT CASE WHEN ci.报价模式 = '总价包干' THEN 1 END) > 0 AND COUNT(DISTINCT CASE WHEN ci.报价模式 = '按量结算' THEN 1 END) > 0 THEN '混合计价' WHEN COUNT(DISTINCT CASE WHEN ci.报价模式 = '总价包干' THEN 1 END) > 0 THEN '总价包干' WHEN COUNT(DISTINCT CASE WHEN ci.报价模式 = '按量结算' THEN 1 END) > 0 THEN '按量结算' ELSE '未知' END AS pricingMode FROM CONTRACT c LEFT JOIN CONTRACT_ITEM ci ON c.合同编号 = ci.合同编号 WHERE c.合同编号 IN
#{id}
GROUP BY c.合同编号
